const headers = $input.first().json.headers || [];
const rows = $input.first().json.data || [];

// Mapeo básico de columnas comunes
const mapping = {
  'RFC': 'rfc',
  'rfc': 'rfc',
  'Nombre': 'nombre',
  'nombre': 'nombre',
  'Cliente': 'nombre',
  'Monbre': 'nombre',
  'Monto': 'monto',
  'monto': 'monto',
  'Importe': 'monto',
  'Cantidad': 'monto',
  'Saldo': 'monto',
  'Concepto': 'concepto',
  'concepto': 'concepto',
  'Tipo': 'concepto',
  'Servicio': 'concepto',
  'Descripcion': 'concepto',
  'Telefono': 'telefono',
  'telefono': 'telefono',
  'Teléfono': 'telefono',
  'Celular': 'telefono',
  'Email': 'email',
  'email': 'email',
  'Correo': 'email'
};

// Mapear filas al formato requerido
const mappedRows = rows.map(row => {
  const obj = {};
  row.forEach((value, index) => {
    const header = headers[index];
    const mappedField = mapping[header];
    if (mappedField && value !== undefined && value !== null && value !== '') {
      obj[mappedField] = value;
    }
  });
  // Convertir monto a número
  if (obj.monto) {
    obj.monto = typeof obj.monto === 'number' ? obj.monto : parseFloat(String(obj.monto).replace(/[$,\s]/g, '')) || 0;
  }
  // Limpiar teléfono
  if (obj.telefono) {
    obj.telefono = String(obj.telefono).replace(/\D/g, '');
  }
  return obj;
}).filter(r => r.rfc); // Solo filas con RFC

return { headers, rows: mappedRows };

// PLANTILLA DEL CLIENTE
const plantilla = `Estimado {CLIENTE},\n\nGracias por elegirnos, le hago llegar el reporte de honorarios actualizado.\n\nSaldo pendiente {MONTO}. Apreciamos su pronto pago:\n\nBeneficiario: {BENEFICIARIO}\nInstitución: {BANCO}\nCuenta CLABE: {CLABE}\n\nNo dudes en ponerte en contacto con nosotros si tienes alguna pregunta.\n\n¡Que tenga un excelente día!\n\n{PERSONA}\n{DEPTO}\n{TEL}\n{EMAIL}\n{WEB}`;

// DATOS DEL DESPACHO (configurar aquí)
const config = {
  beneficiario: 'Oscar Abel Zambrano Rentería',
  banco: 'Banco Inbursa S.A.',
  clabe: '036 028 5005 7775 7743',
  persona: 'Fernanda Romo',
  depto: 'Dpto. de Impuestos',
  tel: '+52 (664) 733 8483',
  email: 'impuestos@bajatax.com',
  web: 'www.bajatax.com',
  apiUrl: 'http://localhost:3001'
};

// Datos del cliente (del workflow)
const client = $('Get Cliente Collecta').first().json;
const operations = $('Get Historial Collecta').first().json || [];

// Calcular totales
const pendientes = operations.filter(o => !o.fechaPago);
const pagados = operations.filter(o => o.fechaPago);
const totalPendiente = pendientes.reduce((sum, p) => sum + Number(p.monto || 0), 0);
const totalPagado = pagados.reduce((sum, p) => sum + Number(p.monto || 0), 0);

// Nombre del cliente (prioridad: nombre en Collecta > nombre en Excel)
const nombreCliente = (client?.nombre || $input.first().json.nombre || 'Cliente').trim();

// Formatear monto
const montoFormateado = totalPendiente > 0 
  ? `$${totalPendiente.toLocaleString('es-MX', {minimumFractionDigits: 0, maximumFractionDigits: 0})} MXN`
  : '$0 MXN';

// Reemplazar variables en plantilla
let mensaje = plantilla
  .replace(/{CLIENTE}/g, nombreCliente)
  .replace(/{MONTO}/g, montoFormateado)
  .replace(/{BENEFICIARIO}/g, config.beneficiario)
  .replace(/{BANCO}/g, config.banco)
  .replace(/{CLABE}/g, config.clabe)
  .replace(/{PERSONA}/g, config.persona)
  .replace(/{DEPTO}/g, config.depto)
  .replace(/{TEL}/g, config.tel)
  .replace(/{EMAIL}/g, config.email)
  .replace(/{WEB}/g, config.web);

// Agregar historial si hay operaciones
if (operations.length > 0) {
  let detalleOps = '\n\n--- RESUMEN DE OPERACIONES ---';

  if (pendientes.length > 0) {
    detalleOps += '\n*Pendiente:*';
    pendientes.forEach(p => {
      detalleOps += `\n• ${p.tipo || 'Servicio'}: $${Number(p.monto || 0).toLocaleString('es-MX')}`;
    });
  }

  if (pagados.length > 0) {
    detalleOps += '\n*Pagado (3 meses):*';
    pagados.forEach(p => {
      detalleOps += `\n• ${p.tipo || 'Servicio'}: $${Number(p.monto || 0).toLocaleString('es-MX')}`;
    });
  }

  mensaje += detalleOps;
}

// Agregar link al PDF
const pdfUrl = `${config.apiUrl}/api/cobranza/cliente/${$input.first().json.rfc}/pdf`;
mensaje += `\n\nVer estado de cuenta: ${pdfUrl}`;

// Teléfono (prioridad: teléfono en Collecta > teléfono en Excel)
const telefono = (client?.telefono || $input.first().json.telefono || '').replace(/\D/g, '');

// Agregar código de país si no lo tiene
let telefonoConCodigo = telefono;
if (telefonoConCodigo && !telefonoConCodigo.startsWith('52')) {
  telefonoConCodigo = '52' + telefonoConCodigo;
}

// Generar URL wa.me
const waUrl = telefonoConCodigo 
  ? `https://wa.me/${telefonoConCodigo}?text=${encodeURIComponent(mensaje)}`
  : null;

return {
  rfc: $input.first().json.rfc,
  nombre: nombreCliente,
  telefono: telefono,
  telefonoConCodigo: telefonoConCodigo,
  totalPendiente: totalPendiente,
  totalPagado: totalPagado,
  pendientesCount: pendientes.length,
  pagadosCount: pagados.length,
  mensaje: mensaje,
  waUrl: waUrl,
  pdfUrl: pdfUrl,
  clienteEncontrado: !!client
};
